#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long w1,w2,x1,x2,M;
        scanf("%lld %lld %lld %lld %lld",&w1,&w2,&x1,&x2,&M);
        long long inc = w2 - w1;
        long long minInc = x1 * M;
        long long maxInc = x2 * M;
        if(inc >= minInc && inc <= maxInc) printf("1\n");
        else printf("0\n");
    }
    return 0;
}

